!function($){"use strict";$(function(){const $wrapper=$(".agencies_wrapper");if(!$wrapper.length)return;const $grid=$wrapper.find(".agencies_grid"),$cards=$grid.find("[data-agency-card]"),$searchInput=$wrapper.find(".agencies_search_input"),$sortSelect=$wrapper.find(".agencies_sort_select"),$emptyState=$grid.find(".agency_empty_state");let filterTimer=null;function normalize(value){return String(value||"").toLowerCase()}function sortCards(){if(!$cards.length)return;const sortValue=$sortSelect.length?String($sortSelect.val()||"new"):"new",cards=$cards.get();cards.sort(function(a,b){const $a=$(a),$b=$(b),createdA=parseInt($a.data("created"),10)||0,createdB=parseInt($b.data("created"),10)||0,feeA=parseFloat($a.data("fee"))||0,feeB=parseFloat($b.data("fee"))||0,titleA=normalize($a.data("title")),titleB=normalize($b.data("title"));return"name"===sortValue?titleA.localeCompare(titleB):"fee_low"===sortValue?feeA-feeB:"fee_high"===sortValue?feeB-feeA:createdB-createdA});$grid.find(".agency_empty_state").before(cards)}function filterCards(){const query=normalize($searchInput.val());let visibleCount=0;$cards.each(function(){const $card=$(this),title=normalize($card.data("title")),owner=normalize($card.data("owner")),matches=!query||-1!==title.indexOf(query)||-1!==owner.indexOf(query);$card.toggleClass("is-hidden",!matches),matches&&(visibleCount+=1)}),$emptyState.length&&$emptyState.toggleClass("is-hidden",visibleCount>0)}function scheduleFilter(){filterTimer&&clearTimeout(filterTimer),filterTimer=setTimeout(function(){sortCards(),filterCards()},120)}$searchInput.length&&$searchInput.on("input",scheduleFilter),$sortSelect.length&&$sortSelect.on("change",scheduleFilter),sortCards(),filterCards()})}(jQuery);